class RGBColor:
    def __init__(self, r, g, b):
        # Clamp values to 0-255 range
        self.r = max(0, min(255, r))
        self.g = max(0, min(255, g))
        self.b = max(0, min(255, b))

    def to_hex(self):
        return '#{:02X}{:02X}{:02X}'.format(self.r, self.g, self.b)

    def to_tuple(self):
        return (self.r, self.g, self.b)

# Example: Yellow color
yellow = RGBColor(255, 255, 0)
print(f"RGB: {yellow.to_tuple()}")      # (255, 255, 0)
print(f"Hex: {yellow.to_hex()}")        # #FFFF00

// Linear interpolation function
float lerp(float start, float end, float t) {
    // t is between 0.0 and 1.0
    return start + (end - start) * t;
}

// Interpolate between two RGB colors
typedef struct { unsigned char r, g, b; } RGB;

RGB lerpColor(RGB c1, RGB c2, float t) {
    RGB result;
    result.r = (unsigned char)lerp(c1.r, c2.r, t);
    result.g = (unsigned char)lerp(c1.g, c2.g, t);
    result.b = (unsigned char)lerp(c1.b, c2.b, t);
    return result;
}

// Example: Fade from red to blue over 10 frames
RGB red = {255, 0, 0};
RGB blue = {0, 0, 255};
for (int i = 0; i <= 10; i++) {
    float t = i / 10.0f;
    RGB frame = lerpColor(red, blue, t);
    printf("Frame %d: R=%d, G=%d, B=%d\n", i, frame.r, frame.g, frame.b);
}

public class RGBAColor {
    private int r, g, b, a;  // 0-255 each

    public RGBAColor(int r, int g, int b, int a) {
        this.r = clamp(r);
        this.g = clamp(g);
        this.b = clamp(b);
        this.a = clamp(a);
    }

    private int clamp(int value) {
        return Math.max(0, Math.min(255, value));
    }

    // Blend two colors using alpha compositing
    public static RGBAColor blend(RGBAColor bg, RGBAColor fg) {
        float alpha = fg.a / 255.0f;

        int r = (int)(fg.r * alpha + bg.r * (1 - alpha));
        int g = (int)(fg.g * alpha + bg.g * (1 - alpha));
        int b = (int)(fg.b * alpha + bg.b * (1 - alpha));

        return new RGBAColor(r, g, b, 255);
    }

    public static void main(String[] args) {
        // Red at 50% opacity over white background
        RGBAColor white = new RGBAColor(255, 255, 255, 255);
        RGBAColor semiRed = new RGBAColor(255, 0, 0, 128);

        RGBAColor result = blend(white, semiRed);
        System.out.println("Blended: RGB(" + result.r + ", " + result.g + ", " + result.b + ")");
    }
}
